<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0, user-scalable=yes">
  <title>Ubuntu Dark Desktop</title>
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    body {
      font-family: 'Ubuntu', 'Segoe UI', system-ui, -apple-system, sans-serif;
      overflow: hidden;
      height: 100vh;
      width: 100vw;
      background: #2c001e; /* fallback deep purple */
    }

    /* desktop root */
    #desktop {
      position: relative;
      width: 100vw;
      height: 100vh;
      background: radial-gradient(circle at 20% 30%, #3b1b3a, #1e0f1f);
      background-size: cover;
      display: flex;
      flex-direction: column;
      overflow: hidden;
    }

    /* taskbar / dock */
    #taskbar {
      position: absolute;
      bottom: 0;
      left: 0;
      width: 100%;
      height: 56px;
      background: rgba(20, 10, 20, 0.85);
      backdrop-filter: blur(16px);
      -webkit-backdrop-filter: blur(16px);
      border-top: 1px solid rgba(255, 255, 255, 0.15);
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 24px;
      padding: 0 24px;
      z-index: 100;
      box-shadow: 0 -4px 20px rgba(0, 0, 0, 0.6);
    }

    .taskbar-btn {
      background: rgba(255, 255, 255, 0.08);
      border: 1px solid rgba(255, 255, 255, 0.2);
      color: #f0e6f6;
      font-size: 0.95rem;
      font-weight: 500;
      padding: 10px 24px;
      border-radius: 30px;
      cursor: pointer;
      display: flex;
      align-items: center;
      gap: 8px;
      transition: all 0.2s ease;
      letter-spacing: 0.3px;
      backdrop-filter: blur(4px);
      background: rgba(45, 25, 45, 0.7);
      box-shadow: 0 2px 8px rgba(0,0,0,0.3);
    }

    .taskbar-btn:hover {
      background: rgba(90, 50, 90, 0.8);
      border-color: rgba(255, 255, 255, 0.4);
      color: white;
      box-shadow: 0 4px 14px rgba(180, 100, 180, 0.4);
    }

    .taskbar-btn i {
      font-style: normal;
      font-size: 1.2rem;
    }

    /* windows container */
    .desktop-windows {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: calc(100% - 56px);
      pointer-events: none;
      z-index: 10;
    }

    /* generic window style */
    .app-window {
      position: absolute;
      min-width: 380px;
      min-height: 280px;
      width: 560px;
      height: 420px;
      background: rgba(30, 20, 30, 0.92);
      backdrop-filter: blur(20px);
      -webkit-backdrop-filter: blur(20px);
      border: 1px solid rgba(255, 255, 255, 0.25);
      border-radius: 16px;
      box-shadow: 0 20px 40px rgba(0, 0, 0, 0.7), 0 0 0 1px rgba(255, 255, 255, 0.1);
      display: flex;
      flex-direction: column;
      overflow: hidden;
      pointer-events: auto;
      color: #e0d8e8;
      font-size: 0.9rem;
      resize: both;
      overflow: auto;
      transition: box-shadow 0.2s;
    }

    .app-window:hover {
      box-shadow: 0 24px 48px rgba(0,0,0,0.8), 0 0 0 1px rgba(255,255,255,0.2);
    }

    .window-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      background: rgba(40, 25, 40, 0.8);
      padding: 10px 16px;
      border-bottom: 1px solid rgba(255, 255, 255, 0.15);
      font-weight: 500;
      user-select: none;
      cursor: default;
    }

    .window-title {
      display: flex;
      align-items: center;
      gap: 8px;
      font-size: 0.95rem;
      color: #f0e0f0;
    }

    .win-close {
      background: rgba(255, 255, 255, 0.1);
      border: none;
      color: #ffb8b8;
      font-size: 1.2rem;
      width: 28px;
      height: 28px;
      border-radius: 50%;
      display: flex;
      align-items: center;
      justify-content: center;
      cursor: pointer;
      transition: all 0.2s;
      font-weight: bold;
      background: rgba(60, 30, 30, 0.7);
      border: 1px solid rgba(255, 100, 100, 0.4);
    }

    .win-close:hover {
      background: #c0392b;
      color: white;
      border-color: #ff6b6b;
      box-shadow: 0 0 12px rgba(255, 80, 80, 0.6);
    }

    .window-content {
      flex: 1;
      padding: 12px;
      overflow: auto;
      display: flex;
      flex-direction: column;
      background: rgba(20, 12, 22, 0.7);
    }

    /* files specific */
    .files-nav {
      display: flex;
      align-items: center;
      gap: 10px;
      margin-bottom: 12px;
      background: rgba(255,255,255,0.05);
      padding: 8px 12px;
      border-radius: 10px;
    }

    #files-up {
      background: rgba(255,255,255,0.15);
      border: none;
      color: white;
      font-size: 1.2rem;
      width: 34px;
      height: 34px;
      border-radius: 8px;
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      transition: 0.2s;
    }

    #files-up:hover {
      background: rgba(180, 130, 180, 0.5);
    }

    #files-path {
      flex: 1;
      background: rgba(0,0,0,0.4);
      padding: 6px 12px;
      border-radius: 20px;
      font-family: monospace;
      font-size: 0.9rem;
      color: #d4c0e0;
      border: 1px solid rgba(255,255,255,0.2);
    }

    .file-list {
      display: flex;
      flex-wrap: wrap;
      gap: 12px;
      align-content: flex-start;
    }

    .fs-item {
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      width: 90px;
      padding: 10px 4px;
      background: rgba(255,255,255,0.05);
      border-radius: 12px;
      cursor: pointer;
      transition: 0.2s;
      text-align: center;
      word-break: break-word;
      border: 1px solid transparent;
      font-size: 0.8rem;
      color: #ddd;
    }

    .fs-item:hover {
      background: rgba(140, 90, 140, 0.35);
      border-color: rgba(255,255,255,0.3);
    }

    .fs-item.folder {
      font-weight: 500;
    }

    .fs-item .icon {
      font-size: 2rem;
      margin-bottom: 4px;
    }

    /* notepad tabs */
    .tabs-container {
      display: flex;
      align-items: center;
      gap: 4px;
      margin-bottom: 10px;
      flex-wrap: wrap;
    }

    #tabs {
      display: flex;
      gap: 4px;
      flex-wrap: wrap;
      flex: 1;
    }

    .tab {
      background: rgba(70, 40, 70, 0.7);
      padding: 6px 14px;
      border-radius: 20px;
      cursor: pointer;
      font-size: 0.85rem;
      border: 1px solid rgba(255,255,255,0.2);
      transition: 0.2s;
      white-space: nowrap;
      color: #ccc;
    }

    .tab.active {
      background: #7b4b7b;
      border-color: #d9a0d9;
      color: white;
      font-weight: 600;
    }

    #new-tab {
      background: rgba(255,255,255,0.15);
      border: none;
      color: white;
      font-size: 1.3rem;
      width: 32px;
      height: 32px;
      border-radius: 50%;
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      margin-left: 4px;
    }

    #editor {
      width: 100%;
      flex: 1;
      background: rgba(10, 5, 12, 0.8);
      border: 1px solid rgba(255,255,255,0.2);
      border-radius: 12px;
      padding: 12px;
      color: #f0e0ff;
      font-family: 'Ubuntu Mono', monospace;
      font-size: 0.9rem;
      resize: none;
      outline: none;
    }

    /* positioning windows nicely */
    #files-window { top: 60px; left: 60px; }
    #notepad-window { top: 100px; left: 180px; }
  </style>
</head>
<body>
<div id="desktop">
  <div class="desktop-windows" id="windows-area">
    <!-- windows injected dynamically but we keep static structure with ids -->
    <div id="files-window" class="app-window" style="display: none;">
      <div class="window-header">
        <span class="window-title">📁 Files</span>
        <button class="win-close" data-window="files-window">✕</button>
      </div>
      <div class="window-content">
        <div class="files-nav">
          <button id="files-up" title="Up">⬆️</button>
          <span id="files-path">/</span>
        </div>
        <div id="files-list" class="file-list"></div>
      </div>
    </div>

    <div id="notepad-window" class="app-window" style="display: none;">
      <div class="window-header">
        <span class="window-title">📝 Notepad</span>
        <button class="win-close" data-window="notepad-window">✕</button>
      </div>
      <div class="window-content">
        <div class="tabs-container">
          <div id="tabs"></div>
          <button id="new-tab" title="New Tab">+</button>
        </div>
        <textarea id="editor" placeholder="Start writing..."></textarea>
      </div>
    </div>
  </div>

  <div id="taskbar">
    <button id="open-files" class="taskbar-btn"><i>📂</i> Files</button>
    <button id="open-notepad" class="taskbar-btn"><i>📝</i> Notepad</button>
  </div>
</div>

<script>
  (function() {
    // ----- FAKE FILESYSTEM DATA -----
    const fileSystem = {
      '/': {
        type: 'dir',
        children: {
          'bin': { type: 'dir', children: {} },
          'etc': { type: 'dir', children: { 'hostname': { type: 'file' }, 'resolv.conf': { type: 'file' } } },
          'home': {
            type: 'dir',
            children: {
              'user': {
                type: 'dir',
                children: {
                  'Documents': { type: 'dir', children: { 'notes.txt': { type: 'file' }, 'project.md': { type: 'file' } } },
                  'Downloads': { type: 'dir', children: { 'wallpaper.png': { type: 'file' } } },
                  'Pictures': { type: 'dir', children: { 'avatar.jpg': { type: 'file' } } },
                  '.bashrc': { type: 'file' }
                }
              }
            }
          },
          'usr': { type: 'dir', children: { 'lib': { type: 'dir', children: {} }, 'share': { type: 'dir', children: {} } } },
          'var': { type: 'dir', children: { 'log': { type: 'dir', children: {} } } }
        }
      }
    };

    // ----- STATE -----
    let currentPath = '/';
    let filesWindowVisible = false;
    let notepadWindowVisible = false;

    // Notepad state
    let tabs = [];                 // { id, name, content }
    let activeTabId = null;
    let tabCounter = 0;

    // ----- DOM ELEMENTS -----
    const filesWindow = document.getElementById('files-window');
    const notepadWindow = document.getElementById('notepad-window');
    const filesPathSpan = document.getElementById('files-path');
    const filesListDiv = document.getElementById('files-list');
    const filesUpBtn = document.getElementById('files-up');
    const tabsDiv = document.getElementById('tabs');
    const editorTextarea = document.getElementById('editor');
    const newTabBtn = document.getElementById('new-tab');
    const openFilesBtn = document.getElementById('open-files');
    const openNotepadBtn = document.getElementById('open-notepad');

    // Close buttons
    document.querySelectorAll('.win-close').forEach(btn => {
      btn.addEventListener('click', (e) => {
        const windowId = btn.getAttribute('data-window');
        if (windowId === 'files-window') {
          hideFilesWindow();
        } else if (windowId === 'notepad-window') {
          hideNotepadWindow();
        }
      });
    });

    // ----- WINDOW VISIBILITY -----
    function showFilesWindow() {
      filesWindow.style.display = 'flex';
      filesWindowVisible = true;
      renderCurrentDirectory();
    }

    function hideFilesWindow() {
      filesWindow.style.display = 'none';
      filesWindowVisible = false;
    }

    function showNotepadWindow() {
      notepadWindow.style.display = 'flex';
      notepadWindowVisible = true;
      renderTabs();
      if (activeTabId) {
        const active = tabs.find(t => t.id === activeTabId);
        if (active) {
          editorTextarea.value = active.content;
        } else if (tabs.length > 0) {
          switchTab(tabs[0].id);
        }
      } else if (tabs.length > 0) {
        switchTab(tabs[0].id);
      }
    }

    function hideNotepadWindow() {
      // Save current editor content to active tab before hiding
      if (activeTabId) {
        const activeTab = tabs.find(t => t.id === activeTabId);
        if (activeTab) {
          activeTab.content = editorTextarea.value;
          persistTabs();
        }
      }
      notepadWindow.style.display = 'none';
      notepadWindowVisible = false;
    }

    // Launcher buttons
    openFilesBtn.addEventListener('click', () => {
      if (!filesWindowVisible) {
        showFilesWindow();
      } else {
        // bring to front? just ensure visible
        filesWindow.style.display = 'flex';
      }
    });

    openNotepadBtn.addEventListener('click', () => {
      if (!notepadWindowVisible) {
        showNotepadWindow();
      } else {
        notepadWindow.style.display = 'flex';
      }
    });

    // ----- FILESYSTEM HELPERS -----
    function getNodeAtPath(pathStr) {
      if (pathStr === '/') return fileSystem['/'];
      const parts = pathStr.split('/').filter(p => p.length > 0);
      let node = fileSystem['/'];
      for (const part of parts) {
        if (!node || node.type !== 'dir' || !node.children || !node.children[part]) return null;
        node = node.children[part];
      }
      return node;
    }

    function renderCurrentDirectory() {
      const node = getNodeAtPath(currentPath);
      filesPathSpan.textContent = currentPath;
      filesListDiv.innerHTML = '';

      if (!node || node.type !== 'dir') {
        filesListDiv.innerHTML = '<div style="color:#aaa; padding:20px;">Invalid directory</div>';
        return;
      }

      const entries = node.children || {};
      const names = Object.keys(entries).sort((a,b) => {
        const aDir = entries[a].type === 'dir' ? 0 : 1;
        const bDir = entries[b].type === 'dir' ? 0 : 1;
        if (aDir !== bDir) return aDir - bDir;
        return a.localeCompare(b);
      });

      if (names.length === 0) {
        filesListDiv.innerHTML = '<div style="color:#aaa; padding:20px;">Empty folder</div>';
        return;
      }

      names.forEach(name => {
        const entry = entries[name];
        const itemDiv = document.createElement('div');
        itemDiv.className = 'fs-item' + (entry.type === 'dir' ? ' folder' : '');
        const icon = entry.type === 'dir' ? '📁' : '📄';
        itemDiv.innerHTML = `<span class="icon">${icon}</span><span>${name}</span>`;

        if (entry.type === 'dir') {
          itemDiv.addEventListener('dblclick', (e) => {
            e.stopPropagation();
            navigateToFolder(name);
          });
        } else {
          itemDiv.addEventListener('dblclick', (e) => {
            alert(`File: ${name} (no preview)`);
          });
        }
        filesListDiv.appendChild(itemDiv);
      });
    }

    function navigateToFolder(folderName) {
      const node = getNodeAtPath(currentPath);
      if (!node || !node.children || !node.children[folderName] || node.children[folderName].type !== 'dir') return;

      if (currentPath === '/') {
        currentPath = '/' + folderName;
      } else {
        currentPath = currentPath.replace(/\/$/, '') + '/' + folderName;
      }
      renderCurrentDirectory();
    }

    function navigateUp() {
      if (currentPath === '/') return;
      const parts = currentPath.split('/').filter(p => p.length > 0);
      parts.pop();
      currentPath = '/' + parts.join('/');
      if (currentPath === '') currentPath = '/';
      renderCurrentDirectory();
    }

    filesUpBtn.addEventListener('click', navigateUp);

    // ----- NOTEPAD LOGIC WITH LOCALSTORAGE -----
    function generateTabName(index) {
      return `Tab ${index}`;
    }

    function persistTabs() {
      const data = {
        tabs: tabs,
        activeTabId: activeTabId,
        counter: tabCounter
      };
      localStorage.setItem('ubuntu-notepad-tabs', JSON.stringify(data));
    }

    function loadTabsFromStorage() {
      const stored = localStorage.getItem('ubuntu-notepad-tabs');
      if (stored) {
        try {
          const parsed = JSON.parse(stored);
          if (parsed.tabs && Array.isArray(parsed.tabs)) {
            tabs = parsed.tabs;
            tabCounter = parsed.counter || tabs.length;
            activeTabId = parsed.activeTabId || (tabs.length > 0 ? tabs[0].id : null);
            return;
          }
        } catch (e) {}
      }
      // default: create one empty tab
      tabCounter = 1;
      const newTab = { id: Date.now() + '-' + Math.random(), name: generateTabName(1), content: '' };
      tabs = [newTab];
      activeTabId = newTab.id;
      persistTabs();
    }

    function switchTab(tabId) {
      // save current content
      if (activeTabId) {
        const currentTab = tabs.find(t => t.id === activeTabId);
        if (currentTab) {
          currentTab.content = editorTextarea.value;
        }
      }
      activeTabId = tabId;
      const tab = tabs.find(t => t.id === tabId);
      if (tab) {
        editorTextarea.value = tab.content || '';
      }
      renderTabs();
      persistTabs();
    }

    function createNewTab() {
      tabCounter++;
      const newId = Date.now() + '-' + Math.random();
      const newTab = { id: newId, name: generateTabName(tabCounter), content: '' };
      tabs.push(newTab);
      activeTabId = newId;
      editorTextarea.value = '';
      renderTabs();
      persistTabs();
    }

    function closeTab(tabId, e) {
      e.stopPropagation();
      if (tabs.length <= 1) {
        // keep at least one tab, just clear it
        const onlyTab = tabs[0];
        onlyTab.content = '';
        editorTextarea.value = '';
        activeTabId = onlyTab.id;
        renderTabs();
        persistTabs();
        return;
      }
      const index = tabs.findIndex(t => t.id === tabId);
      if (index === -1) return;
      tabs.splice(index, 1);
      if (activeTabId === tabId) {
        const newActive = tabs[Math.min(index, tabs.length-1)];
        activeTabId = newActive ? newActive.id : null;
        if (activeTabId) {
          const activeTab = tabs.find(t => t.id === activeTabId);
          editorTextarea.value = activeTab ? activeTab.content : '';
        } else {
          editorTextarea.value = '';
        }
      }
      renderTabs();
      persistTabs();
    }

    function renderTabs() {
      tabsDiv.innerHTML = '';
      tabs.forEach(tab => {
        const tabEl = document.createElement('div');
        tabEl.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
        tabEl.textContent = tab.name;
        tabEl.addEventListener('click', () => switchTab(tab.id));

        const closeSpan = document.createElement('span');
        closeSpan.textContent = ' ✕';
        closeSpan.style.marginLeft = '6px';
        closeSpan.style.fontSize = '0.8rem';
        closeSpan.style.opacity = '0.7';
        closeSpan.addEventListener('click', (e) => closeTab(tab.id, e));
        tabEl.appendChild(closeSpan);

        tabsDiv.appendChild(tabEl);
      });
    }

    // Editor changes auto-save to active tab
    editorTextarea.addEventListener('input', () => {
      if (activeTabId) {
        const activeTab = tabs.find(t => t.id === activeTabId);
        if (activeTab) {
          activeTab.content = editorTextarea.value;
          persistTabs();
        }
      }
    });

    newTabBtn.addEventListener('click', createNewTab);

    // Initialize everything
    function init() {
      loadTabsFromStorage();
      // initial path render
      renderCurrentDirectory();
      // windows hidden by default
      filesWindow.style.display = 'none';
      notepadWindow.style.display = 'none';
      filesWindowVisible = false;
      notepadWindowVisible = false;

      // ensure editor reflects active tab if notepad opened later
      if (activeTabId) {
        const tab = tabs.find(t => t.id === activeTabId);
        if (tab) editorTextarea.value = tab.content;
      }
    }

    init();

    // Additional: make windows draggable? Not required but nice; but we keep minimal.
    // Ensure windows are at least 360x240 via CSS min-width/min-height.
    // Also handle resize observer maybe.
  })();
</script>
</body>
</html>
